parameters.message:
=A high-priority IT support ticket has been raised via the Telegram Helpdesk Bot and requires immediate attention.

Employee Details:
Name: {{$json.Name}}
Employee ID: {{$json.EmployeeID}}
Priority Score: {{$json.priority_score}} / 100

Issue Summary:
{{$json.issue_summary}}

Please action this ticket as soon as possible.

parameters.jsCode:
// Get raw output from AI Agent
let raw = $json.output ?? "";

// Remove markdown code fences if the model wrapped the JSON
raw = String(raw).replace(/```json/g, '').replace(/```/g, '').trim();

// Safe fallback reply — always non-empty so Telegram never gets a blank message
const FALLBACK_REPLY = "Hi! I'm Aria, your IT Helpdesk Assistant 👋 I had a small hiccup processing that. Could you send your message again? I'm here to help!";

// Parse JSON safely
let parsed;

try {
  parsed = JSON.parse(raw);
} catch (error) {
  // If the raw output is plain readable text (agent skipped JSON), use it directly
  const usableRaw = raw && raw.length > 5 && raw.length < 4000 ? raw : FALLBACK_REPLY;
  return [
    {
      json: {
        parse_success: false,
        Name: "",
        EmployeeID: "",
        reply_to_user: usableRaw,
        priority_score: 0,
        issue_summary: "",
        error: "JSON parsing failed — used raw output as reply"
      }
    }
  ];
}

// Extract fields from nested ticket_data
const name         = parsed.ticket_data?.name              || "";
const employeeId   = parsed.ticket_data?.employee_id       || "";
const issueSummary = parsed.ticket_data?.issue_description || parsed.resolution_notes || "";

// Ensure reply_to_user is never empty
const replyText = (parsed.reply_to_user && parsed.reply_to_user.trim().length > 0)
  ? parsed.reply_to_user
  : FALLBACK_REPLY;

// Return flat structure for downstream nodes
return [
  {
    json: {
      parse_success: true,
      Name: name,
      EmployeeID: employeeId,
      reply_to_user: replyText,
      priority_score: parsed.priority_score || 0,
      issue_summary: issueSummary
    }
  }
];
